<script setup lang="ts">
import { computed, reactive } from 'vue'
import { useFullscreenElement } from '../lib/useFullscreen'
import { buildSensitivityRows, calculateSmartphoneMemoryDemand, formatCapacity, formatNumber, listScenarioPresets, type SmartphoneDemandInput } from '../lib/smartphoneDemand'
const input = reactive<SmartphoneDemandInput>({ shipmentsMillion: 1200, entrySharePercent: 40, mainstreamSharePercent: 35, premiumSharePercent: 25, entryDramGb: 4, mainstreamDramGb: 8, premiumDramGb: 12, entryNandGb: 128, mainstreamNandGb: 256, premiumNandGb: 512 })
const { targetRef: simulatorRoot, isFullscreen, toggleFullscreen } = useFullscreenElement()
const presets = listScenarioPresets()
function applyPreset(presetInput: SmartphoneDemandInput) { Object.assign(input, presetInput) }
const result = computed(() => calculateSmartphoneMemoryDemand(input))
const shipmentSensitivityRows = computed(() => buildSensitivityRows(input, [-20, -10, 0, 10, 20]))
const maxNand = computed(() => Math.max(...shipmentSensitivityRows.value.map((row) => row.result.totalNandGb)))
const currentScenarioLabel = computed(() => presets.find((preset) => JSON.stringify(preset.input) === JSON.stringify({ ...input }))?.label ?? 'Custom user scenario')
</script>
