v-model.number="input.entrySharePercent" type="number" min="0" max="100" /></label><input v-model.number="input.entrySharePercent" type="range" min="0" max="100" /><div class="quick-chips"><button class="quick-chip" @click="input.entrySharePercent = 20">20%</button><button class="quick-chip" @click="input.entrySharePercent = 40">40%</button><button class="quick-chip" @click="input.entrySharePercent = 70">70%</button></div><p class="impact">Impact: entry-heavy mix lowers weighted content.</p><span class="source-pill">Mix assumption</span></article><article class="control-row"><label>Mainstream share <input v-model.number="input.mainstreamSharePercent" type="number" min="0" max="100" /></label><input v-model.number="input.mainstreamSharePercent" type="range" min="0" max="100" /><div class="quick-chips"><button class="quick-chip" @click="input.mainstreamSharePercent = 25">25%</button><button class="quick-chip" @click="input.mainstreamSharePercent = 35">35%</button><button class="quick-chip" @click="input.mainstreamSharePercent = 50">50%</button></div><p class="impact">Impact: normalized with other segment shares.</p><span class="source-pill">Mix assumption</span></article><article class="control-row"><label>Premium share <input v-model.number="input.premiumSharePercent" type="number" min="0" max="100" /></label><input v-model.number="input.premiumSharePercent" type="range" min="0" max="100" /><div class="quick-chips"><button class="quick-chip" @click="input.premiumSharePercent = 10">10%</button><button class="quick-chip" @click="input.premiumSharePercent = 25">25%</button><button class="quick-chip" @click="input.premiumSharePercent = 45">45%</button></div><p class="impact">Impact: premiumization lifts weighted DRAM/NAND.</p><span class="source-pill">Source-backed product anchors</span></article><article class="control-row"><label>Premium NAND <input v-model.number="input.premiumNandGb" type="number" min="0" step="16" /></label><input v-model.number="input.premiumNandGb" type="range" min="128" max="1024" step="16" /><div class="quick-chips"><button class="quick-chip" @click="input.premiumNandGb = 256">256GB</button><button class="quick-chip" @click="input.premiumNandGb = 512">512GB</button><button class="quick-chip" @click="input.premiumNandGb = 1024">1TB</button></div><p class="impact">Impact: premium storage can dominate NAND uplift.</p><span class="source-pill">Content anchor</span></article><article class="control-row"><label>Premium DRAM <input v-model.number="input.premiumDramGb" type="number" min="0" step="1" /></label><input v-model.number="input.premiumDramGb" type="range" min="4" max="24" step="1" /><div class="quick-chips"><button class="quick-chip" @click="input.premiumDramGb = 8">8GB</button><button class="quick-chip" @click="input.premiumDramGb = 12">12GB</button><button class="quick-chip" @click="input.premiumDramGb = 16">16GB</button></div><p class="impact">Impact: on-device AI raises DRAM content.</p><span class="source-pill">Content anchor</span></article></div></div><div class="sensitivity-bars"><h3>Visual sensitivity</h3><div v-for="row in shipmentSensitivityRows" :key="row.changePercent" class="bar-row"><span>{{ row.changePercent }}% units</span><div class="bar-track"><div class="bar-fill" :style="{ width: `${(row.result.totalNandGb / maxNand) * 100}%` }"></div></div><strong>{{ formatCapacity(row.result.totalNandGb) }}</strong></div><details class="table-wrap"><summary>Exact values</summary><table><tbody><tr v-for="row in shipmentSensitivityRows" :key="row.shipmentsMillion"><td>{{ row.shipmentsMillion }}M units</td><td>{{ formatCapacity(row.result.totalDramGb) }} DRAM</td><td>{{ formatCapacity(row.result.totalNandGb) }} NAND</td></tr></tbody></table></details></div></div><aside class="result-rail"><div class="sticky-result-panel"><span class="primary-result-label">Primary result</span><strong class="primary-result-value">{{ formatCapacity(result.totalNandGb) }}</strong><p class="primary-result-note">NAND demand · {{ currentScenarioLabel }}</p><div class="result-grid"><article><span>Total DRAM</span><strong>{{ formatCapacity(result.totalDramGb) }}</strong></article><article><span>Avg content</span><strong>{{ formatNumber(result.weightedAverageDramGb, 2) }}GB / {{ formatNumber(result.weightedAverageNandGb, 0) }}GB</strong></article></div><p class="note">Segment shares normalize before weighted content calculation.</p></div></aside></div></section></template>
